import React, { useState, useEffect } from "react";
import {
  SectionWrapper,
  Wrapper,
} from "../../components/Styles/RegisterStyles";
import axios from "axios";
import DataTable from "react-data-table-component";
import { FaEllipsisV, FaEye, FaHistory, FaDownload, FaLock } from "react-icons/fa";
import { X } from "lucide-react"; // For close icon
import { Link, useParams } from "react-router-dom";
import SideBar from '../../components/Investor/social/SideBar';
import TopBar from '../../components/Investor/social/TopBar';
import { DataRoomSection } from "../../components/Styles/DataRoomStyle.js";
import { BackButton } from "../../components/Styles/GlobalStyles.js";
import { ArrowLeft } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { API_BASE_URL } from "../../config/config.js";

function DataroomManagementlist() {
  const [open, setOpen] = useState(null);
  const { id } = useParams();
  const navigate = useNavigate();
  document.title = "DataRoom Management Doc- Investor";
  const [showViewPopup, setShowViewPopup] = useState(false);
  const [selectedReport, setSelectedReport] = useState(null);
  const customStyles = {
    table: {
      style: {
        minWidth: "100%",
        boxShadow: "0px 3px 12px rgb(0 0 0 / 16%)",
        borderRadius: "12px",
        overflow: "visible",
      },
    },
    headCells: {
      style: {
        backgroundColor: "#efefef !important",
        fontWeight: "600",
        fontSize: "0.9rem",
        color: "#000 !important",
        whiteSpace: "nowrap",
        overflow: "visible",
      },
    },
    cells: {
      style: {
        whiteSpace: "nowrap",
        textOverflow: "ellipsis",
        backgroundColor: "#fff !important",
        overflow: "visible",
      },
    },
    rows: {
      style: {
        fontSize: "0.8rem",
        fontWeight: "500",
        position: "relative",
        "&:hover": {
          backgroundColor: "#e8f0fe",
        },
      },
      stripedStyle: {
        backgroundColor: "#f4f6f8",
      },
    },
    pagination: {
      style: {
        backgroundColor: "#fafafa",
        padding: "12px 16px",
      },
    },
  };

  var apiURL = API_BASE_URL + "api/user/dataroom/";

  const storedUsername = localStorage.getItem("InvestorData");
  const userLogin = JSON.parse(storedUsername);
  const [searchText, setSearchText] = useState("");
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [records, setRecords] = useState([]);

  useEffect(() => {
    getInvestorDataRoomList();
  }, []);

  const getInvestorDataRoomList = async () => {
    let formData = {
      investor_id: userLogin.id,
      company_id: Number(id),
    };

    try {
      const res = await axios.post(
        apiURL + "getInvestorDataRoomList",
        formData,
        {
          headers: {
            Accept: "application/json",
            "Content-Type": "application/json",
          },
        }
      );

      setRecords(res.data.results);
    } catch (err) {
      console.error("Error fetching data:", err);
    }
  };
  function formatCurrentDate(input) {
    const date = new Date(input);
    if (isNaN(date)) return "";

    const months = [
      "Jan", "Feb", "Mar", "Apr", "May", "Jun",
      "Jul", "Aug", "Sep", "Oct", "Nov", "Dec",
    ];

    const day = date.getDate();
    const month = months[date.getMonth()];
    const year = date.getFullYear();

    const getOrdinal = (n) => {
      if (n >= 11 && n <= 13) return "th";
      switch (n % 10) {
        case 1: return "st";
        case 2: return "nd";
        case 3: return "rd";
        default: return "th";
      }
    };

    let hours = date.getHours();
    const minutes = date.getMinutes().toString().padStart(2, "0");
    const seconds = date.getSeconds().toString().padStart(2, "0");
    const ampm = hours >= 12 ? "PM" : "AM";

    hours = hours % 12;
    hours = hours ? hours : 12;

    return `${month} ${day}${getOrdinal(day)}, ${year}`;
  }
  const filteredData = records && records.length > 0 ? records.filter((item) => {
    const search = searchText.toLowerCase();

    const combinedFields = `
      ${item.company_name || ""}
      ${item.report_type || ""}
      ${item.doc_name || ""}
      ${item.access_status || ""}
      ${item.sent_date ? new Date(item.sent_date).toLocaleDateString() : ""}
    `.toLowerCase();

    return combinedFields.includes(search);
  }) : [];



  const handleBackClick = () => {
    navigate("/investor/company-list");
  };

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = () => {
      if (open !== null) {
        setOpen(null);
      }
    };
    document.addEventListener("click", handleClickOutside);
    return () => {
      document.removeEventListener("click", handleClickOutside);
    };
  }, [open]);

  const toggleDropdown = (rowId, e) => {
    e.stopPropagation();
    setOpen(open === rowId ? null : rowId);
  };
  const handleViewReport = (row) => {
    setSelectedReport(row);
    setShowViewPopup(true);
    setOpen(null); // Close dropdown
  };

  // Handle Download Report
  const handleDownloadReport = async (row) => {
    let formData = {
      investor_id: userLogin.id,
      company_id: Number(id),
      sharereport_id: row.id
    };

    try {
      const res = await axios.post(
        apiURL + "getreportstatusUpdate",
        formData,
        {
          headers: {
            Accept: "application/json",
            "Content-Type": "application/json",
          },
        }
      );
      getInvestorDataRoomList()
      if (row.downloadUrl) {
        window.open(row.downloadUrl, '_blank');
      } else {
        console.error("No download URL available");
        alert("Download URL not available");
      }
      setOpen(null); // Close dropdown
    } catch (err) {
      console.error("Error fetching data:", err);
    }

  };

  return (


    <main>
      <div className='d-flex align-items-start gap-0'>
        <SideBar />
        <div className='d-flex flex-grow-1 flex-column gap-0'>
          <TopBar />
          <SectionWrapper className="d-block p-md-4 p-3">
            <div className="container-fluid">
              <DataRoomSection className="d-flex flex-column gap-3">
                <div className="titleroom flex-wrap  gap-3 d-flex justify-content-between align-items-center border-bottom pb-3">
                  <h4 className="mainh1">Company List</h4>
                </div>
                <div className="d-flex justify-content-end p-0">
                  <input
                    type="search"
                    placeholder="Search Here..."
                    className="textarea_input"
                    value={searchText}
                    onChange={(e) => setSearchText(e.target.value)}
                    style={{
                      padding: "10px",
                      width: "100%",
                      maxWidth: "200px",
                      fontSize: "14px",
                    }}
                  />
                </div>
                <div className="d-flex  flex-column justify-content-between align-items-start tb-box">
                  <style>
                    {`
                        .datatb-report {
                          overflow: visible !important;
                        }
                      `}
                  </style>
                  <DataTable
                    customStyles={customStyles}
                    columns={[
                      {
                        name: "Company Name",
                        selector: (row) => row.company_name, // Changed from row.email
                        sortable: true,
                        cell: (row) => (
                          <div className="d-flex align-items-center">
                            <div className="bg-primary bg-opacity-10 p-2 rounded-circle me-3">
                              <svg
                                xmlns="http://www.w3.org/2000/svg"
                                width="14"
                                height="14"
                                fill="currentColor"
                                className="text-primary"
                                viewBox="0 0 16 16"
                              >
                                {/* Building icon for company name */}
                                <path d="M14.763.075A.5.5 0 0 1 15 .5v15a.5.5 0 0 1-.5.5h-3a.5.5 0 0 1-.5-.5V14h-1v1.5a.5.5 0 0 1-.5.5h-9a.5.5 0 0 1-.5-.5V10H.5a.5.5 0 0 1-.5-.5v-3a.5.5 0 0 1 .5-.5H2V.5a.5.5 0 0 1 .5-.5h12a.5.5 0 0 1 .5.5v3a.5.5 0 0 1-.5.5H14v8.5a.5.5 0 0 1 .5.5h2a.5.5 0 0 1 .5-.5V.575a.5.5 0 0 1-.237.5zM3 1.5v13h8V1.5H3zm10.5 0v13h1V1.5h-1z" />
                              </svg>
                            </div>
                            <span>{row.company_name}</span>{" "}
                            {/* Changed from row.email */}
                          </div>
                        ),
                      },
                      {
                        name: "Doc type",
                        selector: (row) => row.report_type,
                        sortable: true,
                        cell: (row) => (
                          <div className="d-flex align-items-center">
                            <div className="bg-info bg-opacity-10 p-2 rounded me-2">
                              <svg
                                xmlns="http://www.w3.org/2000/svg"
                                width="14"
                                height="14"
                                fill="currentColor"
                                className="text-info"
                                viewBox="0 0 16 16"
                              >
                                {/* Phone icon for company contact */}
                                <path d="M3.654 1.328a.678.678 0 0 1 .736-.128l2.261.904c.329.131.445.507.249.777L5.08 4.58a.678.678 0 0 1-.746.225l-1.01-.303a11.72 11.72 0 0 0 5.516 5.516l.303-1.01a.678.678 0 0 1 .225-.746l1.195-1.195c.27-.196.646-.08.777.249l.904 2.261a.678.678 0 0 1-.128.736l-2.307 2.307c-.329.329-.888.329-1.217 0l-1.927-1.927a13.134 13.134 0 0 1-6.29-6.29L1.328 2.545c-.329-.329-.329-.888 0-1.217L3.654 1.328z" />
                              </svg>
                            </div>
                            <span>{row.report_type}</span>
                          </div>
                        ),
                      },

                      {
                        name: "Sent Date",
                        selector: (row) => row.sent_date, // Changed from percentage
                        sortable: true,
                        cell: (row) => (
                          <div className="d-flex align-items-center">
                            <div className="bg-success bg-opacity-10 p-2 rounded me-2">
                              <svg
                                xmlns="http://www.w3.org/2000/svg"
                                width="14"
                                height="14"
                                fill="currentColor"
                                className="text-success"
                                viewBox="0 0 16 16"
                              >
                                {/* Globe icon for country */}
                                <path d="M8 0a8 8 0 1 0 0 16A8 8 0 0 0 8 0zM4.882 1.731a.482.482 0 0 0 .14.291.487.487 0 0 0 .292.14.49.49 0 0 0 .356 0 .487.487 0 0 0 .292-.14.482.482 0 0 0 .14-.291.484.484 0 0 0-.14-.292.483.483 0 0 0-.292-.14.484.484 0 0 0-.356 0 .483.483 0 0 0-.292.14.484.484 0 0 0-.14.292zM7.5 11.5V12h-4v-1h1v-1h1v-1h1v-1h-1V8h1V7h1V6h1V5h-1V4h1V3h1V2h1v9h-1z" />
                              </svg>
                            </div>
                            <span> {formatCurrentDate(row.sent_date)}</span>{" "}
                            {/* Changed from percentage display */}
                          </div>
                        ),
                      },
                      {
                        name: "Access Status",
                        selector: (row) => row.access_status,
                        sortable: true,
                        cell: (row) => {
                          let color = "";
                          let bgColor = "";

                          if (row.access_status === "Download") {
                            color = "#065f46";
                            bgColor = "#d1fae5";
                          } else if (row.access_status === "Only View") {
                            color = "#1e40af";
                            bgColor = "#dbeafe";
                          } else {
                            color = "#b91c1c";
                            bgColor = "#fee2e2";
                          }

                          return (
                            <span
                              style={{
                                padding: "4px 12px",
                                borderRadius: "12px",
                                fontWeight: 600,
                                color: color,
                                backgroundColor: bgColor,
                                fontSize: "12px",
                                display: "inline-block",
                              }}
                            >
                              {row.access_status === "Download" ? "📥 Download" :
                                row.access_status === "Only View" ? "👁️ View Only" : "⏳ Not Viewed"}
                            </span>
                          );
                        },
                      },
                      {
                        name: "Actions",
                        cell: (row) => (
                          <div className="position-relative" style={{ position: "relative", zIndex: 9999 }}>
                            <button
                              className="btn btn-light btn-sm"
                              onClick={(e) => toggleDropdown(row.id, e)}
                              style={{
                                border: "1px solid #ddd",
                                borderRadius: "6px",
                                padding: "4px 8px",
                                cursor: "pointer",
                              }}
                            >
                              <FaEllipsisV />
                            </button>

                            {open === row.id && (
                              <div
                                className="dropdown-menu show"
                                style={{
                                  position: "absolute",
                                  top: "100%",
                                  right: 0,
                                  left: "auto",
                                  minWidth: "220px",
                                  zIndex: 99999,
                                  borderRadius: "8px",
                                  background: "#fff",
                                  boxShadow: "0 4px 12px rgba(0,0,0,0.15)",
                                  display: "block",
                                  marginTop: "4px",
                                }}
                              >

                                <button
                                  className="dropdown-item"
                                  style={{
                                    display: "flex",
                                    alignItems: "center",
                                    gap: "8px",
                                    padding: "8px 16px",
                                    color: "#333",
                                    textDecoration: "none",
                                    width: "100%",
                                    background: "none",
                                    border: "none",
                                    cursor: "pointer",
                                  }}
                                  onClick={() => handleViewReport(row)}
                                >
                                  <FaEye /> View Report
                                </button>


                                <>

                                  <div className="dropdown-divider" style={{ margin: "4px 0" }}></div>
                                  <button
                                    className="dropdown-item"
                                    style={{
                                      display: "flex",
                                      alignItems: "center",
                                      gap: "8px",
                                      padding: "8px 16px",
                                      color: "#333",
                                      textDecoration: "none",
                                      width: "100%",
                                      background: "none",
                                      border: "none",
                                      cursor: "pointer",
                                    }}
                                    onClick={() => handleDownloadReport(row)}
                                  >
                                    <FaDownload /> Download Report
                                  </button>
                                </>


                              </div>
                            )}
                          </div>
                        ),
                        ignoreRowClick: true,
                        allowOverflow: true,
                        button: true,
                        width: "120px",
                      }
                    ]}
                    className="datatb-report"
                    data={filteredData}
                    pagination
                    highlightOnHover
                    striped
                    responsive
                    paginationRowsPerPageOptions={[10, 25, 50, 100]}
                    paginationComponentOptions={{
                      rowsPerPageText: "Rows per page:",
                      rangeSeparatorText: "of",
                      noRowsPerPage: false,
                      selectAllRowsItem: false,
                    }}
                  />
                </div>
              </DataRoomSection>
            </div>
          </SectionWrapper>
        </div>
      </div>
      {/* View Report Popup */}
      {/* View Report Popup - Professional UI */}
      {showViewPopup && selectedReport && (
        <div
          style={{
            position: "fixed",
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: "rgba(0, 0, 0, 0.75)",
            zIndex: 999999,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            backdropFilter: "blur(8px)",
            animation: "fadeIn 0.3s ease-out",
          }}
          onClick={() => setShowViewPopup(false)}
        >
          <style>
            {`
        @keyframes fadeIn {
          from {
            opacity: 0;
            backdrop-filter: blur(0px);
          }
          to {
            opacity: 1;
            backdrop-filter: blur(8px);
          }
        }
        
        @keyframes slideUp {
          from {
            transform: translateY(30px);
            opacity: 0;
          }
          to {
            transform: translateY(0);
            opacity: 1;
          }
        }
        
        @keyframes pulse {
          0% {
            box-shadow: 0 0 0 0 rgba(204, 0, 0, 0.4);
          }
          70% {
            box-shadow: 0 0 0 10px rgba(204, 0, 0, 0);
          }
          100% {
            box-shadow: 0 0 0 0 rgba(204, 0, 0, 0);
          }
        }
      `}
          </style>

          <div
            style={{
              backgroundColor: "#fff",
              borderRadius: "24px",
              maxWidth: "650px",
              width: "90%",
              maxHeight: "85vh",
              overflowY: "auto",
              boxShadow: "0 25px 50px -12px rgba(0, 0, 0, 0.25)",
              animation: "slideUp 0.3s ease-out",
              fontFamily: "'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif",
            }}
            onClick={(e) => e.stopPropagation()}
          >
            {/* Popup Header with #CC0000 Gradient */}
            <div
              style={{
                padding: "24px 28px",
                background: "linear-gradient(135deg, #CC0000 0%, #8B0000 100%)",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                borderRadius: "24px 24px 0 0",
                position: "relative",
              }}
            >
              <div>
                <h5
                  style={{
                    margin: 0,
                    fontWeight: 700,
                    fontSize: "1.25rem",
                    color: "#fff",
                    letterSpacing: "-0.3px",
                  }}
                >
                  <FaEye
                    style={{
                      marginRight: "10px",
                      fontSize: "1.1rem",
                      verticalAlign: "middle",
                    }}
                  />
                  Report Details
                </h5>
                <p
                  style={{
                    margin: "4px 0 0",
                    fontSize: "0.75rem",
                    color: "rgba(255,255,255,0.8)",
                  }}
                >
                  View complete report information
                </p>
              </div>
              <button
                onClick={() => setShowViewPopup(false)}
                style={{
                  background: "rgba(255,255,255,0.2)",
                  border: "none",
                  cursor: "pointer",
                  padding: "8px",
                  borderRadius: "12px",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  transition: "all 0.2s ease",
                  color: "#fff",
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.background = "rgba(255,255,255,0.3)";
                  e.currentTarget.style.transform = "scale(1.05)";
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background = "rgba(255,255,255,0.2)";
                  e.currentTarget.style.transform = "scale(1)";
                }}
              >
                <X size={20} />
              </button>
            </div>

            {/* Popup Body */}
            <div style={{ padding: "28px" }}>
              {/* Company Information Card */}
              <div
                style={{
                  background: "linear-gradient(135deg, #fff5f5 0%, #fff0f0 100%)",
                  borderRadius: "16px",
                  padding: "20px",
                  marginBottom: "24px",
                  border: "1px solid rgba(204, 0, 0, 0.1)",
                }}
              >
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: "12px",
                    marginBottom: "16px",
                  }}
                >
                  <div
                    style={{
                      width: "40px",
                      height: "40px",
                      background: "linear-gradient(135deg, #CC0000 0%, #8B0000 100%)",
                      borderRadius: "12px",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                    }}
                  >
                    <svg
                      width="20"
                      height="20"
                      viewBox="0 0 24 24"
                      fill="none"
                      xmlns="http://www.w3.org/2000/svg"
                    >
                      <path
                        d="M19 21H5C4.46957 21 3.96086 20.7893 3.58579 20.4142C3.21071 20.0391 3 19.5304 3 19V5C3 4.46957 3.21071 3.96086 3.58579 3.58579C3.96086 3.21071 4.46957 3 5 3H19C19.5304 3 20.0391 3.21071 20.4142 3.58579C20.7893 3.96086 21 4.46957 21 5V19C21 19.5304 20.7893 20.0391 20.4142 20.4142C20.0391 20.7893 19.5304 21 19 21Z"
                        stroke="white"
                        strokeWidth="2"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      />
                      <path
                        d="M12 11C13.1046 11 14 10.1046 14 9C14 7.89543 13.1046 7 12 7C10.8954 7 10 7.89543 10 9C10 10.1046 10.8954 11 12 11Z"
                        stroke="white"
                        strokeWidth="2"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      />
                      <path
                        d="M7 17V16C7 14.9391 7.42143 13.9217 8.17157 13.1716C8.92172 12.4214 9.93913 12 11 12H13C14.0609 12 15.0783 12.4214 15.8284 13.1716C16.5786 13.9217 17 14.9391 17 16V17"
                        stroke="white"
                        strokeWidth="2"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      />
                    </svg>
                  </div>
                  <div>
                    <h6
                      style={{
                        margin: 0,
                        fontSize: "0.85rem",
                        fontWeight: 600,
                        color: "#CC0000",
                        textTransform: "uppercase",
                        letterSpacing: "0.5px",
                      }}
                    >
                      Company Information
                    </h6>
                    <p
                      style={{
                        margin: "4px 0 0",
                        fontSize: "0.7rem",
                        color: "#6c757d",
                      }}
                    >
                      Basic company details
                    </p>
                  </div>
                </div>

                <div
                  style={{
                    display: "grid",
                    gridTemplateColumns: "1fr 1fr",
                    gap: "12px",
                  }}
                >
                  <div>
                    <div
                      style={{
                        fontSize: "0.7rem",
                        color: "#6c757d",
                        marginBottom: "4px",
                      }}
                    >
                      Company Name
                    </div>
                    <div
                      style={{
                        fontSize: "0.9rem",
                        fontWeight: 600,
                        color: "#1e293b",
                      }}
                    >
                      {selectedReport.company_name || "N/A"}
                    </div>
                  </div>
                  <div>
                    <div
                      style={{
                        fontSize: "0.7rem",
                        color: "#6c757d",
                        marginBottom: "4px",
                      }}
                    >
                      Report Type
                    </div>
                    <div
                      style={{
                        fontSize: "0.9rem",
                        fontWeight: 600,
                        color: "#1e293b",
                      }}
                    >
                      {selectedReport.report_type || "N/A"}
                    </div>
                  </div>
                </div>
              </div>

              {/* Report Details Card */}
              <div
                style={{
                  background: "#fff",
                  borderRadius: "16px",
                  padding: "20px",
                  marginBottom: "24px",
                  border: "1px solid #e9ecef",
                  boxShadow: "0 1px 3px rgba(0,0,0,0.05)",
                }}
              >
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: "12px",
                    marginBottom: "16px",
                    borderBottom: "2px solid #f1f5f9",
                    paddingBottom: "12px",
                  }}
                >
                  <div
                    style={{
                      width: "36px",
                      height: "36px",
                      background: "#fff0f0",
                      borderRadius: "10px",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                    }}
                  >
                    <svg
                      width="18"
                      height="18"
                      viewBox="0 0 24 24"
                      fill="none"
                      xmlns="http://www.w3.org/2000/svg"
                    >
                      <path
                        d="M12 8V12L15 15M21 12C21 16.9706 16.9706 21 12 21C7.02944 21 3 16.9706 3 12C3 7.02944 7.02944 3 12 3C16.9706 3 21 7.02944 21 12Z"
                        stroke="#CC0000"
                        strokeWidth="2"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      />
                    </svg>
                  </div>
                  <div>
                    <h6
                      style={{
                        margin: 0,
                        fontSize: "0.85rem",
                        fontWeight: 600,
                        color: "#CC0000",
                        textTransform: "uppercase",
                        letterSpacing: "0.5px",
                      }}
                    >
                      Report Details
                    </h6>
                    <p
                      style={{
                        margin: "4px 0 0",
                        fontSize: "0.7rem",
                        color: "#6c757d",
                      }}
                    >
                      Document information
                    </p>
                  </div>
                </div>

                <div
                  style={{
                    display: "grid",
                    gridTemplateColumns: "1fr 1fr",
                    gap: "16px",
                  }}
                >
                  <div>
                    <div
                      style={{
                        fontSize: "0.7rem",
                        color: "#6c757d",
                        marginBottom: "6px",
                        display: "flex",
                        alignItems: "center",
                        gap: "4px",
                      }}
                    >
                      <span>📅</span> Sent Date
                    </div>
                    <div
                      style={{
                        fontSize: "0.9rem",
                        fontWeight: 500,
                        color: "#1e293b",
                      }}
                    >
                      {formatCurrentDate(selectedReport.sent_date)}
                    </div>
                  </div>
                  <div>
                    <div
                      style={{
                        fontSize: "0.7rem",
                        color: "#6c757d",
                        marginBottom: "6px",
                        display: "flex",
                        alignItems: "center",
                        gap: "4px",
                      }}
                    >
                      <span>🔒</span> Access Status
                    </div>
                    <div>
                      <span
                        style={{
                          padding: "4px 12px",
                          borderRadius: "20px",
                          fontSize: "0.75rem",
                          fontWeight: 600,
                          color:
                            selectedReport.access_status === "Download"
                              ? "#065f46"
                              : selectedReport.access_status === "Not View"
                                ? "#b91c1c"
                                : "#CC0000",
                          backgroundColor:
                            selectedReport.access_status === "Download"
                              ? "#d1fae5"
                              : selectedReport.access_status === "Not View"
                                ? "#fee2e2"
                                : "#fff0f0",
                          display: "inline-block",
                        }}
                      >
                        {selectedReport.access_status === "Download"
                          ? "📥 Downloadable"
                          : selectedReport.access_status === "Only View"
                            ? "👁️ Only View"
                            : selectedReport.access_status === "Not View"
                              ? "🚫 Not View"
                              : "👁️ View Only"}
                      </span>
                    </div>
                  </div>
                </div>
              </div>

              {/* Document Preview Card */}
              {selectedReport.viewUrl && (
                <div
                  style={{
                    background: "linear-gradient(135deg, #fff5f5 0%, #fee2e2 100%)",
                    borderRadius: "16px",
                    padding: "20px",
                    marginBottom: "24px",
                    border: "1px solid #fecaca",
                  }}
                >
                  <div
                    style={{
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "space-between",
                      flexWrap: "wrap",
                      gap: "16px",
                    }}
                  >
                    <div
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: "12px",
                      }}
                    >
                      <div
                        style={{
                          width: "48px",
                          height: "48px",
                          background: "#fff",
                          borderRadius: "12px",
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
                          animation: "pulse 2s infinite",
                        }}
                      >
                        <span style={{ fontSize: "24px" }}>📄</span>
                      </div>
                      <div>
                        <h6
                          style={{
                            margin: 0,
                            fontSize: "0.9rem",
                            fontWeight: 700,
                            color: "#CC0000",
                          }}
                        >
                          Document Ready
                        </h6>
                        <p
                          style={{
                            margin: "4px 0 0",
                            fontSize: "0.75rem",
                            color: "#8B0000",
                          }}
                        >
                          {selectedReport.report_type || "Document"} is ready to view
                        </p>
                      </div>
                    </div>
                    <button
                      onClick={() => window.open(selectedReport.viewUrl, "_blank")}
                      style={{
                        background: "#CC0000",
                        color: "#fff",
                        border: "none",
                        padding: "10px 24px",
                        borderRadius: "12px",
                        fontSize: "0.85rem",
                        fontWeight: 600,
                        cursor: "pointer",
                        display: "flex",
                        alignItems: "center",
                        gap: "8px",
                        transition: "all 0.2s ease",
                        boxShadow: "0 4px 12px rgba(204, 0, 0, 0.3)",
                      }}
                      onMouseEnter={(e) => {
                        e.currentTarget.style.background = "#8B0000";
                        e.currentTarget.style.transform = "translateY(-2px)";
                        e.currentTarget.style.boxShadow = "0 6px 16px rgba(204, 0, 0, 0.4)";
                      }}
                      onMouseLeave={(e) => {
                        e.currentTarget.style.background = "#CC0000";
                        e.currentTarget.style.transform = "translateY(0)";
                        e.currentTarget.style.boxShadow = "0 4px 12px rgba(204, 0, 0, 0.3)";
                      }}
                    >
                      <FaEye /> Open Document
                    </button>
                  </div>
                </div>
              )}

              {/* Investor Information Card */}
              <div
                style={{
                  background: "#f8fafc",
                  borderRadius: "16px",
                  padding: "20px",
                  border: "1px solid #e2e8f0",
                }}
              >
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: "12px",
                    marginBottom: "16px",
                  }}
                >
                  <div
                    style={{
                      width: "36px",
                      height: "36px",
                      background: "#fff0f0",
                      borderRadius: "10px",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                    }}
                  >
                    <svg
                      width="18"
                      height="18"
                      viewBox="0 0 24 24"
                      fill="none"
                      xmlns="http://www.w3.org/2000/svg"
                    >
                      <path
                        d="M20 21V19C20 16.8 18.2 15 16 15H8C5.8 15 4 16.8 4 19V21"
                        stroke="#CC0000"
                        strokeWidth="2"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      />
                      <path
                        d="M12 11C14.2091 11 16 9.20914 16 7C16 4.79086 14.2091 3 12 3C9.79086 3 8 4.79086 8 7C8 9.20914 9.79086 11 12 11Z"
                        stroke="#CC0000"
                        strokeWidth="2"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      />
                    </svg>
                  </div>
                  <div>
                    <h6
                      style={{
                        margin: 0,
                        fontSize: "0.85rem",
                        fontWeight: 600,
                        color: "#CC0000",
                        textTransform: "uppercase",
                        letterSpacing: "0.5px",
                      }}
                    >
                      Investor Information
                    </h6>
                    <p
                      style={{
                        margin: "4px 0 0",
                        fontSize: "0.7rem",
                        color: "#6c757d",
                      }}
                    >
                      Recipient details
                    </p>
                  </div>
                </div>

                <div
                  style={{
                    display: "grid",
                    gridTemplateColumns: "1fr 1fr",
                    gap: "12px",
                  }}
                >
                  <div>
                    <div
                      style={{
                        fontSize: "0.7rem",
                        color: "#6c757d",
                        marginBottom: "4px",
                      }}
                    >
                      Investor Email
                    </div>
                    <div
                      style={{
                        fontSize: "0.85rem",
                        fontWeight: 500,
                        color: "#1e293b",
                        wordBreak: "break-all",
                      }}
                    >
                      {selectedReport.investor_email || "N/A"}
                    </div>
                  </div>
                </div>
              </div>
            </div>

            {/* Popup Footer */}
            <div
              style={{
                padding: "20px 28px",
                borderTop: "1px solid #e9ecef",
                display: "flex",
                justifyContent: "flex-end",
                gap: "12px",
                background: "#fafbfc",
                borderRadius: "0 0 24px 24px",
              }}
            >
              <button
                onClick={() => setShowViewPopup(false)}
                style={{
                  padding: "10px 24px",
                  backgroundColor: "#fff",
                  color: "#475569",
                  border: "1px solid #e2e8f0",
                  borderRadius: "12px",
                  fontSize: "0.85rem",
                  fontWeight: 500,
                  cursor: "pointer",
                  transition: "all 0.2s ease",
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.backgroundColor = "#f8fafc";
                  e.currentTarget.style.borderColor = "#cbd5e1";
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.backgroundColor = "#fff";
                  e.currentTarget.style.borderColor = "#e2e8f0";
                }}
              >
                Close
              </button>
              {selectedReport.access_status === "Download" &&
                selectedReport.downloadUrl && (
                  <button
                    onClick={() => handleDownloadReport(selectedReport)}
                    style={{
                      padding: "10px 24px",
                      backgroundColor: "#CC0000",
                      color: "#fff",
                      border: "none",
                      borderRadius: "12px",
                      fontSize: "0.85rem",
                      fontWeight: 600,
                      cursor: "pointer",
                      display: "flex",
                      alignItems: "center",
                      gap: "8px",
                      transition: "all 0.2s ease",
                      boxShadow: "0 2px 6px rgba(204, 0, 0, 0.3)",
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.backgroundColor = "#8B0000";
                      e.currentTarget.style.transform = "translateY(-1px)";
                      e.currentTarget.style.boxShadow = "0 4px 12px rgba(204, 0, 0, 0.4)";
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.backgroundColor = "#CC0000";
                      e.currentTarget.style.transform = "translateY(0)";
                      e.currentTarget.style.boxShadow = "0 2px 6px rgba(204, 0, 0, 0.3)";
                    }}
                  >
                    <FaDownload /> Download Report
                  </button>
                )}
            </div>
          </div>
        </div>
      )}
    </main>
  );
}

export default DataroomManagementlist;
